package org.apache.camel.component.fix;

import org.apache.camel.Exchange;
import org.apache.camel.Processor;
import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import quickfix.Message;
import quickfix.SessionID;

/**
 * FIX consumer that receives inbound FIX messages and feeds them into Camel routes.
 */
public class FixConsumer extends DefaultConsumer {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        LOG.info("Starting FIX consumer for session: {}", getEndpoint().getSessionID());
        super.doStart();
    }

    @Override
    protected void doStop() throws Exception {
        LOG.info("Stopping FIX consumer for session: {}", getEndpoint().getSessionID());
        super.doStop();
    }

    /**
     * Processes an inbound FIX message by creating an Exchange and routing it through Camel.
     *
     * @param  message   the FIX message received
     * @param  sessionID the FIX session ID
     * @throws Exception if processing fails
     */
    public void onMessage(Message message, SessionID sessionID) throws Exception {
        if (!isStarted()) {
            LOG.warn("Received FIX message but consumer is not started, ignoring: {}", message);
            return;
        }

        LOG.debug("Received FIX message: {} from session: {}", message, sessionID);

        Exchange exchange = getEndpoint().createExchange();
        exchange.getIn().setBody(message);
        exchange.getIn().setHeader(FixConstants.FIX_SESSION_ID, sessionID != null ? sessionID.toString() : null);
        if (sessionID != null) {
            exchange.getIn().setHeader(FixConstants.FIX_SENDER_COMP_ID, sessionID.getSenderCompID());
            exchange.getIn().setHeader(FixConstants.FIX_TARGET_COMP_ID, sessionID.getTargetCompID());
        }

        try {
            String msgType = message.getHeader().getString(quickfix.field.MsgType.FIELD);
            exchange.getIn().setHeader(FixConstants.FIX_MESSAGE_TYPE, msgType);
        } catch (Exception e) {
            LOG.debug("Could not extract MsgType from FIX message", e);
        }

        try {
            getProcessor().process(exchange);
            if (exchange.getException() != null) {
                getExceptionHandler().handleException("Error processing FIX message", exchange, exchange.getException());
            }
        } finally {
            releaseExchange(exchange, false);
        }
    }
}

