52:     @Metadata(label = "advanced")
53:     private LogFactory logFactory;
54:     @Metadata(label = "advanced")
55:     private MessageFactory messageFactory;
56:     @Metadata
57:     private boolean lazyCreateEngines;
58:     @Metadata(defaultValue = "true")
59:     private boolean eagerStopEngines = true;
60: 
61:     public QuickfixjComponent() {
62:     }
63: 
64:     public QuickfixjComponent(CamelContext context) {
65:         super(context);
66:     }
67: 
68:     @Override
69:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
70:         // Look up the engine instance based on the settings file ("remaining")
71:         QuickfixjEngine engine;
72:         lock.lock();
73:         try {
74:             QuickfixjEndpoint endpoint = endpoints.get(uri);
75: 
76:             if (endpoint == null) {
77:                 engine = engines.get(remaining);
78:                 if (engine == null) {
79:                     engine = provisionalEngines.get(remaining);
80:                 }
81:                 if (engine == null) {
82:                     QuickfixjConfiguration configuration = configurations.get(remaining);
83:                     SessionSettings settings;
84:                     if (configuration != null) {
85:                         settings = configuration.createSessionSettings();
86:                     } else {
87:                         settings = QuickfixjEngine.loadSettings(getCamelContext(), remaining);
88:                     }
89:                     Boolean lazyCreateEngineForEndpoint
90:                             = super.getAndRemoveParameter(parameters, PARAMETER_LAZY_CREATE_ENGINE, Boolean.TYPE);
91:                     if (lazyCreateEngineForEndpoint == null) {
92:                         lazyCreateEngineForEndpoint = isLazyCreateEngines();
93:                     }
94:                     engine = new QuickfixjEngine(
95:                             uri, settings, messageStoreFactory, logFactory, messageFactory,
96:                             lazyCreateEngineForEndpoint);
97: 
98:                     // only start engine if CamelContext is already started, otherwise the engines gets started
99:                     // automatic later when CamelContext has been started using the StartupListener
100:                     if (getCamelContext().getStatus().isStarted()) {
101:                         startQuickfixjEngine(engine);
102:                         engines.put(remaining, engine);
103:                     } else {
104:                         // engines to be started later
105:                         provisionalEngines.put(remaining, engine);
106:                     }
107:                 }
108: 
109:                 endpoint = new QuickfixjEndpoint(engine, uri, this);
110:                 endpoint.setConfigurationName(remaining);
111:                 endpoint.setLazyCreateEngine(engine.isLazy());
112:                 engine.addEventListener(endpoint);
113:                 endpoints.put(uri, endpoint);
114:             }
115: 
116:             return endpoint;
117:         } finally {
118:             lock.unlock();
119:         }
120:     }
121: 
122:     @Override
123:     protected void doStop() throws Exception {
124:         // stop engines when stopping component
125:         lock.lock();
126:         try {
127:             for (QuickfixjEngine engine : engines.values()) {
128:                 engine.stop();
129:             }
130:         } finally {
131:             lock.unlock();
132:         }
133:         super.doStop();
134:     }
135: 
136:     @Override
137:     protected void doShutdown() throws Exception {
138:         // cleanup when shutting down
139:         engines.clear();
140:         provisionalEngines.clear();
141:         endpoints.clear();
142:         super.doShutdown();
143:     }
144: 
145:     private void startQuickfixjEngine(QuickfixjEngine engine) {
146:         if (!engine.isLazy()) {
147:             LOG.info("Starting QuickFIX/J engine: {}", engine.getUri());
148:             ServiceHelper.startService(engine);
149:         } else {
150:             LOG.info("QuickFIX/J engine: {} will start lazily", engine.getUri());
151:         }
152:     }
153: 
154:     // Test Support
155:     Map<String, QuickfixjEngine> getEngines() {
156:         return Collections.unmodifiableMap(engines);
157:     }
158: 
159:     // Test Support
160:     Map<String, QuickfixjEngine> getProvisionalEngines() {
161:         return Collections.unmodifiableMap(provisionalEngines);
162:     }
163: 
164:     /**
165:      * To use the given MessageFactory
166:      */
167:     public void setMessageFactory(MessageFactory messageFactory) {
168:         this.messageFactory = messageFactory;
169:     }
170: 
171:     public MessageFactory getMessageFactory() {
172:         return messageFactory;
173:     }
174: 
175:     /**
176:      * To use the given LogFactory
177:      */
178:     public void setLogFactory(LogFactory logFactory) {
179:         this.logFactory = logFactory;
180:     }
181: 
182:     public LogFactory getLogFactory() {
183:         return logFactory;
184:     }
185: 
186:     /**
187:      * To use the given MessageStoreFactory
188:      */
189:     public void setMessageStoreFactory(MessageStoreFactory messageStoreFactory) {
190:         this.messageStoreFactory = messageStoreFactory;
191:     }
192: 
193:     public MessageStoreFactory getMessageStoreFactory() {
194:         return messageStoreFactory;
195:     }
196: 
197:     public Map<String, QuickfixjConfiguration> getConfigurations() {
198:         return configurations;
199:     }
200: 
201:     /**
202:      * To use the given map of pre configured QuickFix configurations mapped to the key
203:      */
204:     public void setConfigurations(Map<String, QuickfixjConfiguration> configurations) {
205:         this.configurations = configurations;
206:     }
207: 
208:     public boolean isLazyCreateEngines() {
209:         return this.lazyCreateEngines;
210:     }
211: 
212:     /**
213:      * If set to true, the engines will be created and started when needed (when first message is send)
214:      */
215:     public void setLazyCreateEngines(boolean lazyCreateEngines) {
216:         this.lazyCreateEngines = lazyCreateEngines;
217:     }
218: 
219:     public boolean isEagerStopEngines() {
220:         return eagerStopEngines;
221:     }
222: 
223:     /**
224:      * Whether to eager stop engines when there are no active consumer or producers using the engine.
225:      *
226:      * For example when stopping a route, then the engine can be stopped as well. And when the route is started, then
227:      * the engine is started again.
228:      *
229:      * This can be turned off to only stop the engines when Camel is shutdown.
230:      */
231:     public void setEagerStopEngines(boolean eagerStopEngines) {
232:         this.eagerStopEngines = eagerStopEngines;
233:     }
234: 
235:     @Override
236:     public void onCamelContextStarted(CamelContext camelContext, boolean alreadyStarted) throws Exception {
237:         // only start quickfix engines when CamelContext have finished starting
238:         lock.lock();
239:         try {
240:             for (QuickfixjEngine engine : engines.values()) {
241:                 startQuickfixjEngine(engine);
242:             }
243:             for (Map.Entry<String, QuickfixjEngine> entry : provisionalEngines.entrySet()) {
244:                 startQuickfixjEngine(entry.getValue());
245:                 engines.put(entry.getKey(), entry.getValue());
246:             }
247:             provisionalEngines.clear();
248:         } finally {
249:             lock.unlock();
250:         }
251:     }
252: 
253:     public void ensureEngineStarted(QuickfixjEngine engine) {
254:         // only start engine after provisional engines is no longer in use
255:         // as they are used for holding created engines during bootstrap of Camel
256:         if (provisionalEngines.isEmpty()) {
257:             ServiceHelper.startService(engine);
258:         }
259:     }
260: }
