17: package org.apache.camel.component.quickfixj;
18: 
19: import org.apache.camel.Endpoint;
20: import org.apache.camel.Exchange;
21: import org.apache.camel.Message;
22: import org.apache.camel.Processor;
23: import org.apache.camel.support.DefaultConsumer;
24: import org.quickfixj.QFJException;
25: import org.slf4j.Logger;
26: import org.slf4j.LoggerFactory;
27: import quickfix.Session;
28: import quickfix.SessionID;
29: 
30: public class QuickfixjConsumer extends DefaultConsumer {
31: 
32:     private static final Logger LOG = LoggerFactory.getLogger(QuickfixjConsumer.class);
33: 
34:     public QuickfixjConsumer(Endpoint endpoint, Processor processor) {
35:         super(endpoint, processor);
36:     }
37: 
38:     @Override
39:     public QuickfixjEndpoint getEndpoint() {
40:         return (QuickfixjEndpoint) super.getEndpoint();
41:     }
42: 
43:     @Override
44:     protected void doStart() throws Exception {
45:         getEndpoint().addConsumer(this);
46:         getEndpoint().ensureInitialized();
47:         super.doStart();
48:     }
49: 
50:     @Override
51:     protected void doStop() throws Exception {
52:         getEndpoint().removeConsumer(this);
53:         super.doStop();
54:     }
55: 
56:     public void onExchange(Exchange exchange) {
57:         if (isStarted()) {
58:             try {
59:                 getProcessor().process(exchange);
60: 
61:                 if (exchange.getPattern().isOutCapable() && exchange.hasOut()) {
62:                     sendOutMessage(exchange);
63:                 }
64:             } catch (Exception e) {
65:                 exchange.setException(e);
66:             }
67:         }
68:     }
69: 
70:     private void sendOutMessage(Exchange exchange) throws QFJException {
71:         Message camelMessage = exchange.getMessage();
72:         quickfix.Message quickfixjMessage = camelMessage.getBody(quickfix.Message.class);
73: 
74:         LOG.debug("Sending FIX message reply: {}", quickfixjMessage);
75: 
76:         SessionID messageSessionID = exchange.getIn().getHeader(QuickfixjEndpoint.SESSION_ID_KEY, SessionID.class);
77: 
78:         Session session = getSession(messageSessionID);
79:         if (session == null) {
80:             throw new IllegalStateException("Unknown session: " + messageSessionID);
81:         }
82: 
83:         if (!session.send(quickfixjMessage)) {
84:             throw new CannotSendException("Could not send FIX message reply: " + quickfixjMessage.toString());
85:         }
86:     }
87: 
88:     Session getSession(SessionID messageSessionID) {
89:         return Session.lookupSession(messageSessionID);
90:     }
91: }
