17: package org.apache.camel.component.quickfixj;
18: 
19: import java.util.concurrent.Callable;
20: 
21: import org.apache.camel.Endpoint;
22: import org.apache.camel.Exchange;
23: import org.apache.camel.support.DefaultProducer;
24: import org.slf4j.Logger;
25: import org.slf4j.LoggerFactory;
26: import quickfix.Message;
27: import quickfix.MessageUtils;
28: import quickfix.Session;
29: import quickfix.SessionID;
30: 
31: public class QuickfixjProducer extends DefaultProducer {
32:     public static final String CORRELATION_TIMEOUT_KEY = "CorrelationTimeout";
33:     public static final String CORRELATION_CRITERIA_KEY = "CorrelationCriteria";
34: 
35:     private static final Logger LOG = LoggerFactory.getLogger(QuickfixjProducer.class);
36: 
37:     public QuickfixjProducer(Endpoint endpoint) {
38:         super(endpoint);
39:     }
40: 
41:     @Override
42:     public QuickfixjEndpoint getEndpoint() {
43:         return (QuickfixjEndpoint) super.getEndpoint();
44:     }
45: 
46:     @Override
47:     protected void doStart() throws Exception {
48:         getEndpoint().addProducer();
49:         super.doStart();
50:     }
51: 
52:     @Override
53:     protected void doStop() throws Exception {
54:         getEndpoint().removeProducer();
55:         super.doStop();
56:     }
57: 
58:     @Override
59:     public void process(Exchange exchange) throws Exception {
60:         try {
61:             getEndpoint().ensureInitialized();
62:             sendMessage(exchange, exchange.getIn());
63:         } catch (Exception e) {
64:             exchange.setException(e);
65:         }
66:     }
67: 
68:     void sendMessage(Exchange exchange, org.apache.camel.Message camelMessage) throws Exception {
69:         Message message = camelMessage.getBody(Message.class);
70:         LOG.debug("Sending FIX message: {}", message);
71: 
72:         SessionID messageSessionID = getEndpoint().getSID();
73:         if (messageSessionID == null) {
74:             messageSessionID = MessageUtils.getSessionID(message);
75:         }
76: 
77:         Session session = getSession(messageSessionID);
78:         if (session == null) {
79:             throw new IllegalStateException("Unknown session: " + messageSessionID);
80:         }
81: 
82:         Callable<Message> callable = null;
83: 
84:         if (exchange.getPattern().isOutCapable()) {
85:             MessageCorrelator messageCorrelator = getEndpoint().getEngine().getMessageCorrelator();
86:             callable = messageCorrelator.getReply(exchange);
87:         }
88: 
89:         if (!session.send(message)) {
90:             throw new CannotSendException("Cannot send FIX message: " + message.toString());
91:         }
92: 
