17: package org.apache.camel.component.log;
18: 
19: import java.util.Locale;
20: import java.util.Map;
21: 
22: import org.apache.camel.Endpoint;
23: import org.apache.camel.LoggingLevel;
24: import org.apache.camel.spi.CamelLogger;
