33: 
34: /**
35:  * The <a href="http://camel.apache.org/log.html">Log Component</a> is for logging message exchanges via the underlying
36:  * logging mechanism.
37:  */
38: @org.apache.camel.spi.annotations.Component("log")
39: public class LogComponent extends DefaultComponent {
40: 
41:     private static final Logger LOG = LoggerFactory.getLogger(LogComponent.class);
42: 
43:     private ExchangeFormatter defaultExchangeFormatter;
44: 
45:     @Metadata(label = "advanced", autowired = true)
46:     private ExchangeFormatter exchangeFormatter;
47:     @Metadata
48:     private boolean sourceLocationLoggerName;
49: 
50:     public LogComponent() {
51:     }
52: 
53:     @Override
54:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
55:         LoggingLevel level = getLoggingLevel(parameters);
56:         Logger providedLogger = getLogger(parameters);
57: 
58:         if (providedLogger == null) {
59:             // try to look up the logger in registry
60:             Map<String, Logger> availableLoggers = getCamelContext().getRegistry().findByTypeWithName(Logger.class);
61:             if (availableLoggers.size() == 1) {
62:                 providedLogger = availableLoggers.values().iterator().next();
63:                 LOG.info("Using custom Logger: {}", providedLogger);
64:             } else if (availableLoggers.size() > 1) {
65:                 LOG.info("More than one {} instance found in the registry. Falling back to creating logger from URI {}.",
66:                         Logger.class.getName(), uri);
67:             }
68:         }
69: 
70:         // first, try to pick up the ExchangeFormatter from the registry
71:         ExchangeFormatter logFormatter
72:                 = getCamelContext().getRegistry().lookupByNameAndType("logFormatter", ExchangeFormatter.class);
73:         if (logFormatter != null) {
74:             setProperties(logFormatter, parameters);
75:         } else if (exchangeFormatter != null) {
76:             // do not set properties, the exchangeFormatter is explicitly set, therefore the
77:             // user would have set its properties explicitly too
78:             logFormatter = exchangeFormatter;
79:         }
80: 
81:         LogEndpoint endpoint = new LogEndpoint(uri, this);
82:         endpoint.setLevel(level.name());
83:         endpoint.setSourceLocationLoggerName(sourceLocationLoggerName);
84:         endpoint.setExchangeFormatter(logFormatter);
85:         setProperties(endpoint, parameters);
86: 
87:         if (providedLogger == null) {
88:             String loggerName = endpoint.isSourceLocationLoggerName() ? getLineNumberLoggerName(endpoint) : null;
89:             if (loggerName == null) {
90:                 loggerName = remaining;
91:             }
92:             endpoint.setLoggerName(loggerName);
93:         } else {
94:             endpoint.setProvidedLogger(providedLogger);
95:         }
96: 
97:         return endpoint;
98:     }
99: 
100:     /**
101:      * Gets the logging level, will default to use INFO if no level parameter provided.
102:      */
103:     protected LoggingLevel getLoggingLevel(Map<String, Object> parameters) {
104:         String levelText = getAndRemoveParameter(parameters, "level", String.class);
105:         if (levelText != null) {
106:             return LoggingLevel.valueOf(levelText.toUpperCase(Locale.ENGLISH));
107:         } else {
108:             return LoggingLevel.INFO;
109:         }
110:     }
111: 
112:     /**
113:      * Gets optional {@link Logger} instance from parameters. If non-null, the provided instance will be used as
114:      * {@link Logger} in {@link CamelLogger}
115:      *
116:      * @param  parameters the parameters
117:      * @return            the Logger object from the parameter
118:      */
119:     protected Logger getLogger(Map<String, Object> parameters) {
120:         return getAndRemoveOrResolveReferenceParameter(parameters, "logger", Logger.class);
121:     }
122: 
123:     public ExchangeFormatter getExchangeFormatter() {
124:         return exchangeFormatter;
125:     }
126: 
127:     /**
128:      * Sets a custom {@link ExchangeFormatter} to convert the Exchange to a String suitable for logging. If not
129:      * specified, we default to {@link DefaultExchangeFormatter}.
130:      */
131:     public void setExchangeFormatter(ExchangeFormatter exchangeFormatter) {
132:         this.exchangeFormatter = exchangeFormatter;
133:     }
134: 
135:     public boolean isSourceLocationLoggerName() {
136:         return sourceLocationLoggerName;
137:     }
138: 
139:     /**
140:      * If enabled then the source location of where the log endpoint is used in Camel routes, would be used as logger
141:      * name, instead of the given name. However, if the source location is disabled or not possible to resolve then the
142:      * existing logger name will be used.
143:      */
144:     public void setSourceLocationLoggerName(boolean sourceLocationLoggerName) {
145:         this.sourceLocationLoggerName = sourceLocationLoggerName;
146:     }
147: 
148:     /**
149:      * Gets the default shared exchange formatter.
150:      */
151:     public ExchangeFormatter getDefaultExchangeFormatter() {
152:         return defaultExchangeFormatter;
153:     }
154: 
155:     @Override
156:     protected void doInit() throws Exception {
157:         DefaultExchangeFormatter def = new DefaultExchangeFormatter();
158:         def.setShowExchangePattern(true);
159:         def.setSkipBodyLineSeparator(true);
160:         def.setShowBody(true);
161:         def.setShowBodyType(true);
162:         def.setStyle(DefaultExchangeFormatter.OutputStyle.Default);
163:         def.setMaxChars(10000);
164:         this.defaultExchangeFormatter = def;
165:     }
166: }
