26: /**
27:  * A default implementation of {@link org.apache.camel.Producer} for implementation inheritance, which can process
28:  * {@link Exchange}s asynchronously.
29:  */
30: public abstract class DefaultAsyncProducer extends DefaultProducer implements AsyncProducer {
31: 
32:     public DefaultAsyncProducer(Endpoint endpoint) {
33:         super(endpoint);
34:     }
35: 
36:     @Override
37:     public void process(Exchange exchange) throws Exception {
38:         AsyncProcessorAwaitManager awaitManager
39:                 = PluginHelper.getAsyncProcessorAwaitManager(exchange.getContext());
40:         awaitManager.process(this, exchange);
41:     }
