43:     @Override
44:     public CompletableFuture<Exchange> processAsync(Exchange exchange) {
45:         AsyncCallbackToCompletableFutureAdapter<Exchange> callback = new AsyncCallbackToCompletableFutureAdapter<>(exchange);
46:         process(exchange, callback);
47:         return callback.getFuture();
48:     }
49: }
