package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import quickfix.Message;
import quickfix.Session;
import quickfix.SessionID;

/**
 * FIX producer that sends outbound FIX messages from Camel exchanges.
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            Message message = exchange.getIn().getBody(Message.class);
            if (message == null) {
                throw new IllegalArgumentException("Exchange body must be a quickfix.Message instance");
            }

            String sessionIdStr = getEndpoint().getSessionID();
            SessionID sessionID;
            if (sessionIdStr != null && !sessionIdStr.isEmpty()) {
                sessionID = new SessionID(sessionIdStr);
            } else {
                // Try to derive SessionID from message headers
                String senderCompID = exchange.getIn().getHeader(FixConstants.FIX_SENDER_COMP_ID, String.class);
                String targetCompID = exchange.getIn().getHeader(FixConstants.FIX_TARGET_COMP_ID, String.class);
                String fixVersion = getEndpoint().getConfiguration().getFixVersion();
                if (senderCompID != null && targetCompID != null) {
                    sessionID = new SessionID(fixVersion, senderCompID, targetCompID);
                } else {
                    throw new IllegalStateException(
                            "Cannot determine FIX session: no sessionID configured and no sender/target comp IDs in headers");
                }
            }

            LOG.debug("Sending FIX message to session {}: {}", sessionID, message);

            Session session = Session.lookupSession(sessionID);
            if (session == null) {
                throw new IllegalStateException("No FIX session found for session ID: " + sessionID);
            }

            boolean sent = session.send(message);
            if (!sent) {
                throw new IllegalStateException("Failed to send FIX message to session: " + sessionID);
            }

            LOG.debug("FIX message sent successfully to session: {}", sessionID);
        } catch (Exception e) {
            exchange.setException(e);
        }
        callback.done(true);
        return true;
    }
}

