n configuration) {\n        super(uri, component);\n        this.configuration = configuration;\n    }\n\n    @Override\n    public FixComponent getComponent() {\n        return (FixComponent) super.getComponent();\n    }\n\n    @Override\n    public Producer createProducer() throws Exception {\n        return new FixProducer(this);\n    }\n\n    @Override\n    public Consumer createConsumer(Processor processor) throws Exception {\n        FixConsumer consumer = new FixConsumer(this, processor);\n        configureConsumer(consumer);\n        return consumer;\n    }\n\n    public String getSessionID() {\n        return sessionID;\n    }\n\n    /**\n     * The FIX session identifier in the format: BeginString:SenderCompID->TargetCompID (e.g.\n     * FIX.4.2:SENDER->TARGET).\n     */\n    public void setSessionID(String sessionID) {\n        this.sessionID = sessionID;\n    }\n\n    public FixConfiguration getConfiguration() {\n        return configuration;\n    }\n\n    /**\n     * The FIX configuration.\n     */\n    public void setConfiguration(FixConfiguration configuration) {\n        this.configuration = configuration;\n    }\n}\n", "numLines": 89, "startLine": 1, "totalLines": 89}}

